index 6846f76..61d3e14 100644
--- a/retrofit/src/main/java/retrofit2/ParameterHandler.java
+++ b/retrofit/src/main/java/retrofit2/ParameterHandler.java
@@ -18,6 +18,7 @@ package retrofit2;
 import java.io.IOException;
 import java.lang.reflect.Array;
 import java.lang.reflect.Method;
+import java.nio.charset.StandardCharsets;
 import java.util.Map;
 import java.util.Objects;
 import javax.annotation.Nullable;
@@ -201,7 +202,18 @@ abstract class ParameterHandler<T> {
                   + "'.");
         }

-        builder.addQueryParam(entryKey, convertedEntryValue, encoded);
+        if (!encoded) {
+          // URL-encode the key to handle special characters (e.g., filter[name] → filter%5Bname%5D),
+          // consistent with how query parameter values are encoded.
+          entryKey = java.net.URLEncoder.encode(entryKey, StandardCharsets.UTF_8)
+              .replace("+", "%20");
+          // Also encode the value so we can use the pre-encoded path (encoded=true).
+          convertedEntryValue = java.net.URLEncoder.encode(convertedEntryValue, StandardCharsets.UTF_8)
+              .replace("+", "%20");
+          builder.addQueryParam(entryKey, convertedEntryValue, true);
+        } else {
+          builder.addQueryParam(entryKey, convertedEntryValue, encoded);
+        }
